17	  ticker: string;
18	  side: 'YES' | 'NO';
19	  entry_price: number;           // what we would have paid
20	  simulated_contracts: number;   // Kelly-sized contracts
21	  simulated_cost: number;        // entry_price * contracts
22	  forecast_high_f: number;
23	  implied_temp_f: number;
24	  gap_f: number;
25	  kelly_fraction?: number;       // raw Kelly fraction before halving
26	  model_spread?: number;         // spread between forecast models (°F)
27	  model_confidence?: 'high' | 'medium' | 'low';
28	  status: 'open' | 'won' | 'lost' | 'expired';
29	  settlement_value?: string;     // actual temp recorded
30	  pnl?: number;                  // profit/loss in dollars
31	  created_at: string;
32	  settled_at?: string;
33	}
34	
35	const PAPER_BANKROLL = 1000;      // simulated bankroll for Kelly sizing
36	const KELLY_FRACTION = 0.5;     // half-Kelly for safety
37	const MIN_CONTRACTS = 5;
38	const MAX_CONTRACTS = 50;
39	
40	/**
41	 * Estimate win probability based on edge (gap) and model spread.
42	 */
43	function estimateWinProbability(gapF: number, spread: number | null): number {
44	  const absGap = Math.abs(gapF);
45	  const s = spread ?? 999; // treat unknown spread as low confidence
46	
47	  if (absGap >= 5 && s <= 2) return 0.72;
48	  if (absGap >= 3 && s <= 2) return 0.65;
49	  if (absGap >= 3 && s <= 4) return 0.58;
50	  if (absGap >= 2 && s <= 2) return 0.60;
51	  return 0.55;
52	}
53	
54	/**
55	 * Calculate half-Kelly position size.
56	 * Returns { contracts, kellyFraction } or null if no edge (negative Kelly).
57	 */
58	function kellySize(entryPrice: number, gapF: number, spread: number | null): { contracts: number; kellyFraction: number } | null {
59	  const pWin = estimateWinProbability(gapF, spread);
60	  const odds = (1 / entryPrice) - 1; // net odds (e.g. price=0.40 → odds=1.5)
61	  const kellyFraction = (pWin * odds - (1 - pWin)) / odds;
62	
63	  if (kellyFraction <= 0) return null; // no edge — skip trade
64	
65	  const halfKelly = kellyFraction * KELLY_FRACTION;
66	  const dollarSize = halfKelly * PAPER_BANKROLL;
67	  const contracts = Math.floor(dollarSize / entryPrice);
68	  const clamped = Math.max(MIN_CONTRACTS, Math.min(MAX_CONTRACTS, contracts));
69	
70	  return { contracts: clamped, kellyFraction };
71	}
72	
73	function ensureDataDir() {
74	  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
75	}
76	
77	function readTrades(): PaperTrade[] {
78	  ensureDataDir();
79	  try {
80	    if (fs.existsSync(PAPER_FILE)) return JSON.parse(fs.readFileSync(PAPER_FILE, 'utf8'));
81	  } catch { /* ignore */ }
82	  return [];
83	}
84	
85	function writeTrades(trades: PaperTrade[]) {
86	  fs.writeFileSync(PAPER_FILE, JSON.stringify(trades, null, 2));
87	}
